// Command side: validates and changes state, returns no data (or just an id/ack).
interface PlaceOrderCommand { orderId: string; customerId: string; lines: Line[]; }

class OrderCommandHandler {
  constructor(private repo: AggregateRepository<Order>) {}
  async handle(cmd: PlaceOrderCommand): Promise<void> {
    const order = Order.place(cmd.orderId, cmd.customerId, cmd.lines); // invariants here
    await this.repo.save(order); // persists emitted events
  }
}

// Query side: returns denormalized data, never mutates. Different model entirely.
interface OrderSummaryView { orderId: string; customerName: string; total: number; status: string; }
class OrderQueryHandler {
  constructor(private readDb: ReadDatabase) {}
  getSummary(orderId: string): Promise<OrderSummaryView> {
    return this.readDb.fetchOne('order_summaries', orderId); // a flat, pre-joined row
  }
}

type DomainEvent =
  | { type: 'AccountOpened'; balance: number }
  | { type: 'MoneyDeposited'; amount: number }
  | { type: 'MoneyWithdrawn'; amount: number };

class Account {
  private balance = 0;
  private version = 0;

  // Rebuild state by folding over history (left-fold / reduce).
  static fromHistory(events: DomainEvent[]): Account {
    const a = new Account();
    for (const e of events) a.apply(e);
    return a;
  }

  // apply mutates in-memory state; it NEVER validates (history is already true).
  private apply(e: DomainEvent): void {
    switch (e.type) {
      case 'AccountOpened':  this.balance = e.balance; break;
      case 'MoneyDeposited': this.balance += e.amount; break;
      case 'MoneyWithdrawn': this.balance -= e.amount; break;
    }
    this.version++;
  }

  // A command validates, then emits a NEW event (which is then applied + persisted).
  withdraw(amount: number): DomainEvent {
    if (amount > this.balance) throw new Error('Insufficient funds'); // invariant
    const event: DomainEvent = { type: 'MoneyWithdrawn', amount };
    this.apply(event);
    return event; // caller appends this to the event store
  }
}

// A projection that maintains an 'order_summaries' read table.
class OrderSummaryProjection {
  constructor(private readDb: ReadDatabase) {}

  // Called for each event in order. Must be idempotent: store the last processed
  // global_position (checkpoint) so a replay/restart does not double-apply.
  async on(event: StoredEvent): Promise<void> {
    switch (event.type) {
      case 'OrderPlaced':
        await this.readDb.upsert('order_summaries', {
          orderId: event.payload.orderId,
          total: event.payload.total,
          status: 'PLACED',
        });
        break;
      case 'OrderShipped':
        await this.readDb.update('order_summaries', event.payload.orderId, { status: 'SHIPPED' });
        break;
    }
    await this.readDb.saveCheckpoint('order_summaries', event.global_position);
  }
}

// Upcaster: transforms a v1 event into the current v2 on read.
// v1 had a single 'name'; v2 splits into firstName/lastName.
function upcastCustomerRegistered(raw: StoredEvent): CustomerRegisteredV2 {
  if (raw.metadata.schemaVersion === 2) return raw.payload as CustomerRegisteredV2;
  const [firstName, ...rest] = (raw.payload.name as string).split(' ');
  return { firstName, lastName: rest.join(' ') || '', schemaVersion: 2 };
}
// The aggregate/projection only ever sees the current shape, so app code is not
// littered with version checks. The stored events remain immutable and untouched.

