type Event =
  | { type: 'AccountOpened'; openingBalance: number }
  | { type: 'MoneyDeposited'; amount: number }
  | { type: 'MoneyWithdrawn'; amount: number };

class BankAccount {
  private opened = false;
  private balance = 0;
  version = 0;
  // Uncommitted events emitted by commands, to be appended to the store.
  readonly pending: Event[] = [];

  // ----- Rebuild: pure fold over history, NO validation. -----
  static fromHistory(history: Event[]): BankAccount {
    const acc = new BankAccount();
    for (const e of history) acc.apply(e);
    return acc;
  }

  // evolve/apply: event -> state. A fact already happened; never reject here.
  private apply(e: Event): void {
    switch (e.type) {
      case 'AccountOpened':  this.opened = true; this.balance = e.openingBalance; break;
      case 'MoneyDeposited': this.balance += e.amount; break;
      case 'MoneyWithdrawn': this.balance -= e.amount; break;
    }
    this.version++;
  }

  private emit(e: Event): void { this.apply(e); this.pending.push(e); }

  // ----- Commands: validate against current state, then emit. -----
  open(openingBalance: number): void {
    if (this.opened) throw new Error('Already open');
    if (openingBalance < 0) throw new Error('Opening balance cannot be negative');
    this.emit({ type: 'AccountOpened', openingBalance });
  }
  deposit(amount: number): void {
    if (!this.opened) throw new Error('Account not open');
    if (amount <= 0) throw new Error('Deposit must be positive');
    this.emit({ type: 'MoneyDeposited', amount });
  }
  withdraw(amount: number): void {
    if (!this.opened) throw new Error('Account not open');
    if (amount <= 0) throw new Error('Withdraw must be positive');
    if (amount > this.balance) throw new Error('Insufficient funds'); // invariant at COMMAND time
    this.emit({ type: 'MoneyWithdrawn', amount });
  }
  getBalance(): number { return this.balance; }
}

// --- Live command flow ---
const a = new BankAccount();
a.open(100);
a.deposit(50);   // balance 150
a.withdraw(120); // OK: 120 <= 150 -> balance 30
try { a.withdraw(1000); } catch (e) { /* rejected: Insufficient funds, no event emitted */ }
console.log(a.getBalance()); // 30
console.log(a.pending.map(e => e.type)); // ['AccountOpened','MoneyDeposited','MoneyWithdrawn']

// --- Rebuild from a STORED history that includes a past withdrawal ---
const stored: Event[] = [
  { type: 'AccountOpened', openingBalance: 100 },
  { type: 'MoneyDeposited', amount: 50 },
  { type: 'MoneyWithdrawn', amount: 120 },
];
const rebuilt = BankAccount.fromHistory(stored); // apply() never validates -> replays cleanly
console.log(rebuilt.getBalance(), rebuilt.version); // 30 3

// Read model row: { customerId, totalCents, orderCount }
// Projection state row: { name, lastPosition }

class CustomerOrderTotalsProjection {
  constructor(private db: Db) {}
  private readonly name = 'customer_order_totals';

  async handle(event: StoredEvent): Promise<void> {
    // 1) Idempotency / ordering guard via checkpoint.
    const checkpoint = await this.db.getCheckpoint(this.name); // -1 if none
    if (event.globalPosition <= checkpoint) return; // already processed -> skip

    // 2) Apply the event with idempotent, atomic operations.
    switch (event.type) {
      case 'OrderPlaced':
        await this.db.upsertIncrement('customer_order_totals', event.payload.customerId, {
          totalCents: +event.payload.totalCents,
          orderCount: +1,
        });
        break;
      case 'OrderCancelled':
        await this.db.upsertIncrement('customer_order_totals', event.payload.customerId, {
          totalCents: -event.payload.totalCents,
          orderCount: -1,
        });
        break;
      // unknown event types are ignored (tolerant reader)
    }

    // 3) Advance the checkpoint. In a real system steps 2 and 3 are in ONE
    //    transaction so a crash between them cannot double-apply or skip.
    await this.db.setCheckpoint(this.name, event.globalPosition);
  }

  // Rebuild from scratch: reset read model + checkpoint, then replay everything.
  async rebuild(eventStore: EventStore): Promise<void> {
    await this.db.truncate('customer_order_totals');
    await this.db.setCheckpoint(this.name, -1);
    for await (const event of eventStore.readAll()) {
      await this.handle(event);
    }
  }
}

